.casino-card {

  position: relative;

  .casino-card-image {

    /* display: block; */
    width: 100%;

    vertical-align: middle;
    border: 0;
    position: relative;

    height: 525px;

    object-fit: cover;


    @media only screen and (min-width :1068px) {
      height: 575px;
    }



    @media only screen and (max-width : 1067px) {
      height: 725px;
    }


  }

  .casino-card-text-top {
    position: absolute;
    left: 10px;
    top: 20px;
    color: #fdfdfd;
    padding: 0 30px;
    // -webkit-animation: fadeInDown .4s;
    // animation: fadeInDown .4s;

    img {
      height: 55px;
    }
  }

  .casino-card-text {
 
    position: absolute;
    bottom: 20px;
    left: 10px;
    color: #fdfdfd;
    padding: 0 30px;

    h2 {
    white-space: pre;
      font-size: 30px;
        font-weight: 700;
        line-height: 1.1;
        -webkit-animation: fadeInDown .4s;
    animation: fadeInDown .4s;
    }

    p {
      -webkit-animation: fadeInUp .4s;
    animation: fadeInUp .4s;
      text-shadow: 1px 1px #000;
        font-size: 18px;
    }

    

  }



}

/* card */
.card-swiper {
  /* border: 2px solid red; */
  background-repeat: no-repeat;
  background-size: cover;
  background-position: center center;
  box-shadow: rgba(0, 0, 0, 0.5);
  border-radius: 3px;
  overflow: hidden;


  /* position: relative; */
  a {
    display: block;
  }

  span {
    position: absolute;
    top: 20px;
    left: 10px;
    width: 180px !important;
    padding: 0 30px;
  }

  h2 {
    position: absolute;
    bottom: 20px;
    left: 10px;
    padding: 0 30px;
    color: #fff;
    font-size: 30px;
    font-weight: 700;
    text-transform: uppercase;
  }
}



@keyframes fadeInDown {
	from {
		opacity: 0;
		transform: translate3d(0, -80%, 0);
	}
	to {
		opacity: 1;
		transform: translate3d(0, 0, 0);
	}
}

@keyframes fadeInUp {
	from {
		opacity: 0;
		transform: translate3d(0, 20%, 0);
	}
	to {
		opacity: 1;
		transform: translate3d(0, 0, 0);
	}
}
